import type { Meta, StoryObj } from '@storybook/angular';
import { Component, Input, computed, signal } from '@angular/core';
import { HlmAutocompleteInput } from './hlm-autocomplete-input';
import { HlmAutocompleteImports } from './index';

/**
 * Wrapper component that holds autocomplete state for stories.
 */
@Component({
  selector: 'autocomplete-demo',
  standalone: true,
  imports: [HlmAutocompleteImports],
  template: `
    <div
      hlmAutocomplete
      [value]="value()"
      (valueChange)="value.set($event)"
      [search]="search()"
      (searchChange)="search.set($event)"
      [itemToString]="itemToString"
    >
      <hlm-autocomplete-input
        [placeholder]="placeholder"
        [showSearch]="showSearch"
        [showClear]="showClear"
      />
      <hlm-autocomplete-content *hlmAutocompletePortal>
        <hlm-autocomplete-list>
          @for (item of filteredItems(); track item) {
            <hlm-autocomplete-item [value]="item">{{ item }}</hlm-autocomplete-item>
          }
          <hlm-autocomplete-empty>No results found.</hlm-autocomplete-empty>
        </hlm-autocomplete-list>
      </hlm-autocomplete-content>
    </div>
  `,
})
class AutocompleteDemoComponent {
  value = signal<string | null>(null);
  search = signal('');
  @Input() placeholder = 'Search...';
  @Input() showSearch = true;
  @Input() showClear = false;
  itemToString = (item: string): string => item;

  private _items = signal<string[]>([
    'Apple',
    'Banana',
    'Blueberry',
    'Cherry',
    'Grape',
    'Orange',
    'Peach',
    'Strawberry',
  ]);

  filteredItems = computed(() => {
    const s = this.search().toLowerCase();
    const list = this._items();
    if (!s) return list;
    return list.filter((item) => item.toLowerCase().includes(s));
  });
}

const meta: Meta<HlmAutocompleteInput> = {
  component: HlmAutocompleteInput,
  title: 'Components/Autocomplete',
  parameters: {
    docs: {
      description: {
        component:
          'Searchable dropdown: type to filter options and select one. Use hlm-autocomplete (or hlm-autocomplete-search), hlm-autocomplete-input, hlm-autocomplete-content with *hlmAutocompletePortal, hlm-autocomplete-list, hlm-autocomplete-item, and hlm-autocomplete-empty. Optional: groups, separators, labels.',
      },
    },
  },
};
export default meta;

type Story = StoryObj<HlmAutocompleteInput>;

/**
 * Basic autocomplete with search icon and filtered list. Type to filter, click to select.
 */
export const Default: Story = {
  render: () => ({
    template: `<autocomplete-demo />`,
    moduleMetadata: {
      imports: [HlmAutocompleteImports, AutocompleteDemoComponent],
    },
  }),
};

/**
 * With clear button: show a control to clear the current value.
 */
export const WithClearButton: Story = {
  render: () => ({
    template: `<autocomplete-demo [showClear]="true" />`,
    moduleMetadata: {
      imports: [HlmAutocompleteImports, AutocompleteDemoComponent],
    },
  }),
};

/**
 * Without search icon: plain input with no leading search icon.
 */
export const WithoutSearchIcon: Story = {
  render: () => ({
    template: `<autocomplete-demo [showSearch]="false" />`,
    moduleMetadata: {
      imports: [HlmAutocompleteImports, AutocompleteDemoComponent],
    },
  }),
};

/**
 * Custom placeholder.
 */
export const CustomPlaceholder: Story = {
  render: () => ({
    template: `<autocomplete-demo placeholder="Choose a fruit..." />`,
    moduleMetadata: {
      imports: [HlmAutocompleteImports, AutocompleteDemoComponent],
    },
  }),
};

import type { Meta, StoryObj } from '@storybook/angular';
import { Component, signal } from '@angular/core';
import { HlmComboboxImports } from './index';

/**
 * Wrapper for single-select combobox with trigger button.
 */
@Component({
  selector: 'combobox-trigger-demo',
  standalone: true,
  imports: [HlmComboboxImports],
  template: `
    <div
      hlmCombobox
      [value]="selected()"
      (valueChange)="selected.set($event)"
      [itemToString]="itemToString"
      class="w-[280px]"
    >
      <hlm-combobox-trigger>
        <span hlmComboboxValue>Select framework...</span>
      </hlm-combobox-trigger>
      <hlm-combobox-content *hlmComboboxPortal>
        <hlm-combobox-list>
          @for (item of frameworks; track item) {
            <hlm-combobox-item [value]="item">{{ item }}</hlm-combobox-item>
          }
          <hlm-combobox-empty>No results found.</hlm-combobox-empty>
        </hlm-combobox-list>
      </hlm-combobox-content>
    </div>
  `,
})
class ComboboxTriggerDemo {
  selected = signal<string | undefined>(undefined);
  frameworks = ['React', 'Vue', 'Angular', 'Svelte', 'Solid', 'Qwik'];
  itemToString = (item: string): string => item ?? '';
}

/**
 * Wrapper for single-select combobox with searchable input.
 */
@Component({
  selector: 'combobox-input-demo',
  standalone: true,
  imports: [HlmComboboxImports],
  template: `
    <div
      hlmCombobox
      [value]="selected()"
      (valueChange)="selected.set($event)"
      [itemToString]="itemToString"
      class="w-[280px]"
    >
      <hlm-combobox-input placeholder="Search framework..." [showClear]="true" />
      <hlm-combobox-content *hlmComboboxPortal>
        <hlm-combobox-list>
          @for (item of frameworks; track item) {
            <hlm-combobox-item [value]="item">{{ item }}</hlm-combobox-item>
          }
          <hlm-combobox-empty>No results found.</hlm-combobox-empty>
        </hlm-combobox-list>
      </hlm-combobox-content>
    </div>
  `,
})
class ComboboxInputDemo {
  selected = signal<string | undefined>(undefined);
  frameworks = ['React', 'Vue', 'Angular', 'Svelte', 'Solid', 'Qwik'];
  itemToString = (item: string): string => item ?? '';
}

/**
 * Wrapper for multiple-select combobox with chips.
 */
@Component({
  selector: 'combobox-multiple-demo',
  standalone: true,
  imports: [HlmComboboxImports],
  template: `
    <div
      hlmComboboxMultiple
      [value]="selected()"
      (valueChange)="selected.set($event)"
      [itemToString]="itemToString"
      class="w-[320px]"
    >
      <hlm-combobox-chips>
        <hlm-combobox-values>
          @for (val of selected(); track val) {
            <hlm-combobox-chip>{{ val }}</hlm-combobox-chip>
          }
          <input hlmComboboxChipInput placeholder="Select..." />
        </hlm-combobox-values>
      </hlm-combobox-chips>
      <hlm-combobox-content *hlmComboboxPortal>
        <hlm-combobox-list>
          @for (item of frameworks; track item) {
            <hlm-combobox-item [value]="item">{{ item }}</hlm-combobox-item>
          }
          <hlm-combobox-empty>No results found.</hlm-combobox-empty>
        </hlm-combobox-list>
      </hlm-combobox-content>
    </div>
  `,
})
class ComboboxMultipleDemo {
  selected = signal<string[]>([]);
  frameworks = ['React', 'Vue', 'Angular', 'Svelte', 'Solid', 'Qwik'];
  itemToString = (item: string): string => item ?? '';
}

/**
 * Wrapper for combobox with groups and labels.
 */
@Component({
  selector: 'combobox-groups-demo',
  standalone: true,
  imports: [HlmComboboxImports],
  template: `
    <div
      hlmCombobox
      [value]="selected()"
      (valueChange)="selected.set($event)"
      [itemToString]="itemToString"
      class="w-[280px]"
    >
      <hlm-combobox-input placeholder="Select a fruit..." />
      <hlm-combobox-content *hlmComboboxPortal>
        <hlm-combobox-list>
          <hlm-combobox-group>
            <hlm-combobox-label>Citrus</hlm-combobox-label>
            @for (item of citrus; track item) {
              <hlm-combobox-item [value]="item">{{ item }}</hlm-combobox-item>
            }
          </hlm-combobox-group>
          <hlm-combobox-separator />
          <hlm-combobox-group>
            <hlm-combobox-label>Berries</hlm-combobox-label>
            @for (item of berries; track item) {
              <hlm-combobox-item [value]="item">{{ item }}</hlm-combobox-item>
            }
          </hlm-combobox-group>
          <hlm-combobox-empty>No results found.</hlm-combobox-empty>
        </hlm-combobox-list>
      </hlm-combobox-content>
    </div>
  `,
})
class ComboboxGroupsDemo {
  selected = signal<string | undefined>(undefined);
  citrus = ['Lemon', 'Lime', 'Orange', 'Grapefruit'];
  berries = ['Strawberry', 'Blueberry', 'Raspberry', 'Blackberry'];
  itemToString = (item: string): string => item ?? '';
}

